import{_ as t,o as n,c as r,ag as i}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Datenimport & -export","description":"","frontmatter":{},"headers":[],"relativePath":"de/account/data.md","filePath":"de/account/data.md"}'),a={name:"de/account/data.md"};function o(l,e,d,s,p,u){return n(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="datenimport-export" tabindex="-1">Datenimport &amp; -export <a class="header-anchor" href="#datenimport-export" aria-label="Permalink to &quot;Datenimport &amp; -export&quot;">​</a></h1><p>Importieren Sie bestehende Daten in MyCompanyDesk und exportieren Sie Ihre Aufzeichnungen zur Sicherung oder Verwendung in anderen Tools.</p><h2 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h2><h3 id="csv-import" tabindex="-1">CSV-Import <a class="header-anchor" href="#csv-import" aria-label="Permalink to &quot;CSV-Import&quot;">​</a></h3><p>Importieren Sie Daten aus CSV-Dateien für:</p><ul><li><strong>Kunden</strong> — Name, E-Mail, Telefon, Adresse, USt.-Nummer</li><li><strong>Rechnungen</strong> — Rechnungsdetails mit Positionen</li><li><strong>Ausgaben</strong> — Ausgabendatensätze mit Kategorien</li><li><strong>Projekte</strong> — Projektnamen und Details</li><li><strong>Objekte</strong> — Vermögenswertdatensätze</li></ul><h3 id="so-importieren-sie" tabindex="-1">So importieren Sie <a class="header-anchor" href="#so-importieren-sie" aria-label="Permalink to &quot;So importieren Sie&quot;">​</a></h3><ol><li>Gehen Sie zu <strong>Profil &gt; Import</strong></li><li>Wählen Sie den <strong>Datentyp</strong>, den Sie importieren möchten</li><li>Laden Sie Ihre <strong>CSV-Datei</strong> hoch</li><li><strong>Spalten zuordnen</strong> — Ordnen Sie Ihre CSV-Spaltenüberschriften den MyCompanyDesk-Feldern zu</li><li><strong>Vorschau</strong> — Überprüfen Sie die Daten vor dem Import</li><li><strong>Bestätigen</strong> — Klicken Sie auf Import, um die Datensätze zu erstellen</li></ol><h3 id="import-tipps" tabindex="-1">Import-Tipps <a class="header-anchor" href="#import-tipps" aria-label="Permalink to &quot;Import-Tipps&quot;">​</a></h3><ul><li>Verwenden Sie UTF-8-Kodierung für Ihre CSV-Dateien</li><li>Fügen Sie eine Kopfzeile mit Spaltennamen hinzu</li><li>Datumsformate sollten einheitlich sein (JJJJ-MM-TT empfohlen)</li><li>Betragsfelder sollten den Punkt (.) als Dezimaltrennzeichen verwenden</li><li>Leere Felder werden übersprungen (vorhandene Standardwerte werden verwendet)</li></ul><h3 id="spaltenzuordnung" tabindex="-1">Spaltenzuordnung <a class="header-anchor" href="#spaltenzuordnung" aria-label="Permalink to &quot;Spaltenzuordnung&quot;">​</a></h3><p>Der Import-Assistent zeigt Ihre CSV-Spalten und lässt Sie jede dem entsprechenden MyCompanyDesk-Feld zuordnen. Häufige Zuordnungen:</p><table tabindex="0"><thead><tr><th>CSV-Spalte</th><th>Zuordnung zu</th></tr></thead><tbody><tr><td>Company Name / Name</td><td>Kundenname</td></tr><tr><td>Email</td><td>Kunden-E-Mail</td></tr><tr><td>Street / Address</td><td>Straßenadresse</td></tr><tr><td>ZIP / Postal Code</td><td>Postleitzahl</td></tr><tr><td>City</td><td>Stadt</td></tr><tr><td>VAT / BTW</td><td>USt.-Nummer</td></tr><tr><td>Phone</td><td>Telefonnummer</td></tr></tbody></table><h2 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h2><h3 id="csv-export" tabindex="-1">CSV-Export <a class="header-anchor" href="#csv-export" aria-label="Permalink to &quot;CSV-Export&quot;">​</a></h3><p>Exportieren Sie Ihre Daten als CSV von den jeweiligen Listenseiten:</p><ul><li><strong>Rechnungen</strong> — Alle Rechnungen mit Beträgen, Daten, Status</li><li><strong>Ausgaben</strong> — Alle Ausgaben mit Kategorien und Beträgen</li><li><strong>Kunden</strong> — Ihre Kundendatenbank</li></ul><p>Klicken Sie auf die <strong>Export</strong>-Schaltfläche auf der Listenseite zum Herunterladen.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>CSV-Export erfordert den <strong>Pro</strong>-Tarif oder höher.</p></div><h3 id="dsgvo-datenexport" tabindex="-1">DSGVO-Datenexport <a class="header-anchor" href="#dsgvo-datenexport" aria-label="Permalink to &quot;DSGVO-Datenexport&quot;">​</a></h3><p>Exportieren Sie alle Ihre persönlichen Daten im JSON-Format:</p><ol><li>Gehen Sie zu <strong>Profil &gt; Daten</strong></li><li>Klicken Sie auf <strong>Meine Daten exportieren</strong></li><li>Laden Sie die JSON-Datei mit all Ihren Kontodaten herunter</li></ol><p>Dieser DSGVO-Export umfasst:</p><ul><li>Ihre Profilinformationen</li><li>Alle Rechnungen, Ausgaben, Angebote</li><li>Kundendatensätze</li><li>Projekt- und Zeitdaten</li><li>Einstellungen und Präferenzen</li></ul><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Exportieren Sie Ihre Daten regelmäßig als Sicherungskopie</li><li>Verwenden Sie den CSV-Export, um Daten mit Ihrem Steuerberater zu teilen</li><li>Beim Umstieg von einem anderen Tool verwenden Sie den Import-Assistenten, um Ihre Kundenliste zu migrieren</li><li>Der DSGVO-Export bietet einen vollständigen Schnappschuss Ihrer Daten</li></ul>',26)])])}const g=t(a,[["render",o]]);export{m as __pageData,g as default};
